import React, { useState, useEffect } from 'react'
import Taskcard from './Taskcard'
import axios from 'axios'
import {useNavigate} from 'react-router-dom'

const Tasks = () => {
  const [taskName, settaskName] = useState('')
  const [tasks, setTasks] = useState([])
  const navigate=useNavigate();

  function handleDeleteTask(id) {
    setTasks(prev => {
      const updatedTasks = prev.filter(task => task.id !== id);
      localStorage.setItem('mainTasks', JSON.stringify(updatedTasks)); 
      return updatedTasks;
    });
  }

  async function handleAdd() {
    if (!taskName.trim()) return;

    const newtask = {
      title: taskName
    }
    const res = await axios.post('/api/tasks/addtask', newtask, {
      headers: {
        "Authorization": "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzMTkxNTM1fQ.P_mezNAOUHvpel9hegmNew4_pRexrqGaKdyLuCmESwY"
      }
    })
    console.log(res.data)
    setTasks(prev => {
      const updatedTasks = [...prev, newtask];
      return updatedTasks;
    });

    settaskName('');
  }


  useEffect(() => {
    const storedTasks = async () => {
      const getTask = await axios.get('api/tasks/getalltasks/687e7cd167ec0a24dc89bc80', {
        headers: {
          "Authorization": "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjY4N2U3Y2QxNjdlYzBhMjRkYzg5YmM4MCIsImVtYWlsIjoiYWRtaW5AZ21haWwuY29tIiwiaWF0IjoxNzUzMTkxNTM1fQ.P_mezNAOUHvpel9hegmNew4_pRexrqGaKdyLuCmESwY"
        }
      })
      setTasks(getTask.data);
    }
    storedTasks();
  }, [tasks]);

  return (
    <div className='task-page'>
      <div className='navbar'>
        <div><button onClick={()=>navigate('/home')}>
          <img src='/assets/home.png' />
          </button>
          </div>
      </div>
        <h1 className="tasks-heading">Tasks</h1>
      <div className='task-header'>
        <div>
          <input className='task-name' placeholder='Enter Task title...' value={taskName} onChange={(e) => settaskName(e.target.value)} />
        </div>
        <div>
          <button className='task-add' onClick={handleAdd}>Add</button>
        </div>
      </div>

      <div className='tasks-list'>
        {tasks.map((task) => (
          <Taskcard task={task} key={task._id} handleDeleteTask={handleDeleteTask} />
        ))}
      </div>
      <Stylesheet />
    </div>
  )
}
const Stylesheet = () => {
  return <style>{`
        .navbar{
          position:absolute;
          top:2rem;
          left:2rem;
        }
         button{
           background:none;
           border:none;
        }

        .tasks-heading {
          font-size: 2.5rem;
          text-align: center;
          margin-bottom: 1.5rem;
        }

        .task-page {
          font-family: 'Cedarville Cursive', cursive;
        color: var(--text);
        display: flex;
        justify-content: center;
        flex-direction: column;
        align-items: center;
        padding: 1rem;
        }

        .task-header {
          display: flex;
          flex-direction: row;
          align-items: center;
          justify-content: center;
          gap: 1rem;
          flex-wrap: wrap;
          margin-bottom: 2rem;
        }

        .task-name {
          background-color: var(--secondary-color);
          border: none;
          padding: 10px 15px;
          min-width: 250px;
          border-radius: 5px;
          font-size: 1.2rem;
          font-family: 'Cedarville Cursive', cursive;
          color: var(--text);
          flex: 1 1 250px;
        }

        .task-add {
          background-color: var(--button-color);
          border: none;
          padding: 10px 15px;
          min-width: 100px;
          border-radius: 5px;
          font-size: 1.2rem;
          color: var(--bg-parchment);
          font-family: 'Cedarville Cursive', cursive;
          flex-shrink: 0;
        }

        .task-name::placeholder {
          color: var(--text);
          opacity: 1;
        }

        .tasks-list {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          align-items: flex-start; /* key change: let cards grow independently */
          gap: 1rem;
          padding: 0 1rem;
        }

        @media (max-width: 768px) {
          .task-header {
            flex-direction: column;
            align-items: stretch;
            gap: 0.8rem;
          }

          .task-name,
          .task-add {
            width: 90%;
            font-size: 1rem;
          }

          .tasks-heading {
            font-size: 2rem;
          }
        }

        @media (max-width: 485px) {
          .task-page {
            padding: 0.5rem;
          }

          .navbar{
              display:flex;
              align-items:center;
              justify-content:flex-start;
              width:100%;
              top:25px;
          }
          img{
              height:2rem;
              width:2rem;
          }
          .tasks-heading {
            font-size: 1.5rem;
          }

          .task-name,
          .task-add {
            font-size: 0.95rem;
          }
        }
      `}</style>
}
export default Tasks
